	}

	rows, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("checking rows affected for user %s: %w", userID, err)
	}
	if rows == 0 {
		return fmt.Errorf("no user found with id %s", userID)
	}

	return nil
}
