use rusqlite::{Connection, Result, ToSql};
use std::collections::HashMap;

/// Columns that clients are permitted to update.
const UPDATABLE_COLUMNS: &[&str] = &["display_name", "email", "bio", "avatar_url"];

/// Updates the row in `users` matching `user_id`, setting only the columns
/// present as keys in `fields`. Returns the number of rows affected (0 if no
/// such user exists).
///
/// Only columns listed in `UPDATABLE_COLUMNS` may be updated; any other key
/// is rejected. Values are always bound as parameters, never interpolated.
pub fn update_user_profile(
    conn: &Connection,
    user_id: i64,
    fields: &HashMap<String, String>,
) -> Result<usize> {
    if fields.is_empty() {
        return Ok(0);
    }

    // Reject any key that isn't an allowlisted column. This is what prevents
    // SQL injection through the column-name side of the query.
    for key in fields.keys() {
