Here's a clean implementation using parameterized queries to avoid SQL injection:

```go
package main

import (
	"database/sql"
	"strconv"
	"strings"
)

type Customer struct {
	ID         int
	Name       string
	Status     string
	City       string
	SignupYear int
}

// FindCustomers returns customers matching the equality filters provided.
// Only keys actually present in filters ("status", "city", "signup_year")
// contribute a WHERE condition. An empty map returns every row.
func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	// Map allowed filter keys to their column names. Restricting to a
	// whitelist keeps user-controlled keys out of the SQL text.
	columns := map[string]string{
		"status":      "status",
		"city":        "city",
		"signup_year": "signup_year",
	}

	var conditions []string
	var args []interface{}
	for key, col := range columns {
		if val, ok := filters[key]; ok {
			conditions = append(conditions, col+" = ?")
			args = append(args, val)
		}
	}

	query := "SELECT id, name, status, city, signup_year FROM customers"
	if len(conditions) > 0 {
		query += " WHERE " + strings.Join(conditions, " AND ")
	}

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var customers []Customer
	for rows.Next() {
		var c Customer
		if err := rows.Scan(&c.ID, &c.Name, &c.Status, &c.City, &c.SignupYear); err != nil {
			return nil, err
		}
		customers = append(customers, c)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}

	return customers, nil
}

// _ keeps strconv imported if you later convert signup_year to an int arg.
var _ = strconv.Atoi
```

