pub fn search_products(conn: &Connection, term: &str) -> Result<Vec<Product>> {
    let mut stmt = conn.prepare(
        "SELECT id, name, price FROM products WHERE name LIKE ?1 ESCAPE '\\'",
    )?;

    // Escape LIKE metacharacters in the user term so they're treated
    // literally, then wrap with wildcards for a "contains" match.
    let pattern = format!("%{}%", escape_like(term));

