package main

import (
	"database/sql"
	"fmt"
	"strings"
)

type Customer struct {
	ID         int
	Name       string
	Status     string
	City       string
	SignupYear int
}

// allowedFilters maps the accepted filter keys to their actual column
// names. Only keys present here are ever interpolated into the query
// string, so arbitrary column names can't be injected via the map.
var allowedFilters = map[string]string{
	"status":      "status",
	"city":        "city",
	"signup_year": "signup_year",
}

func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	query := "SELECT id, name, status, city, signup_year FROM customers"

	var conditions []string
	var args []any

	for key, value := range filters {
		column, ok := allowedFilters[key]
		if !ok {
			return nil, fmt.Errorf("unsupported filter key: %q", key)
		}
		conditions = append(conditions, fmt.Sprintf("%s = ?", column))
		args = append(args, value)
	}

	if len(conditions) > 0 {
		query += " WHERE " + strings.Join(conditions, " AND ")
	}

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query customers: %w", err)
	}
	defer rows.Close()

	var customers []Customer
	for rows.Next() {
		var c Customer
		if err := rows.Scan(&c.ID, &c.Name, &c.Status, &c.City, &c.SignupYear); err != nil {
			return nil, fmt.Errorf("scan customer: %w", err)
		}
		customers = append(customers, c)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate customers: %w", err)
	}

	return customers, nil
}
```

