    pool: &PgPool,
    filters: &HashMap<String, String>,
) -> Result<Vec<Customer>, sqlx::Error> {
    let mut qb: QueryBuilder<Postgres> =
        QueryBuilder::new("SELECT id, status, city, signup_year FROM customers");

    let mut first = true;
    let mut push_condition = |qb: &mut QueryBuilder<Postgres>, clause: &str| {
        qb.push(if first { " WHERE " } else { " AND " });
        qb.push(clause);
        first = false;
    };

    if let Some(status) = filters.get("status") {
        push_condition(&mut qb, "status = ");
        qb.push_bind(status);
    }

    if let Some(city) = filters.get("city") {
        push_condition(&mut qb, "city = ");
        qb.push_bind(city);
