            .parse()
            .map_err(|_| sqlx::Error::Decode("invalid signup_year".into()))?;
        push_condition(&mut qb, "signup_year = ");
        qb.push_bind(year);
    }

    qb.build_query_as::<Customer>().fetch_all(pool).await
}
