    pool: &PgPool,
    filters: &HashMap<String, String>,
) -> Result<Vec<Customer>, sqlx::Error> {
    let mut qb: QueryBuilder<sqlx::Postgres> = QueryBuilder::new("SELECT * FROM customers");
