                .parse()
                .map_err(|_| sqlx::Error::Decode(format!("invalid signup_year: {value}").into()))?;
            qb.push_bind(year);
        } else {
            qb.push_bind(value.clone());
        }
    }

    qb.build_query_as::<Customer>().fetch_all(pool).await
}
