Since `fields` supplies column *names* dynamically, those can't be parameterized like values can in `rusqlite` — SQL doesn't allow placeholders for identifiers. To avoid SQL injection through a malicious/unexpected key, I'll validate every key against an allowlist of real `users` columns before building the query, while values are always passed as bound parameters.

```rust
use std::collections::HashMap;
use rusqlite::{Connection, Result, params_from_iter};

/// Columns on `users` that are allowed to be updated this way.
const ALLOWED_COLUMNS: &[&str] = &["name", "email", "bio", "avatar_url", "phone"];

pub fn update_user_profile(
    conn: &Connection,
    user_id: i64,
    fields: &HashMap<String, String>,
) -> Result<usize> {
    if fields.is_empty() {
        return Ok(0);
    }

    let mut set_clauses = Vec::with_capacity(fields.len());
    let mut values: Vec<&str> = Vec::with_capacity(fields.len() + 1);

    for (column, value) in fields {
        if !ALLOWED_COLUMNS.contains(&column.as_str()) {
            return Err(rusqlite::Error::InvalidParameterName(column.clone()));
        }
        set_clauses.push(format!("{column} = ?"));
        values.push(value.as_str());
    }

    let sql = format!(
        "UPDATE users SET {} WHERE id = ?",
        set_clauses.join(", ")
    );

    let user_id_str = user_id.to_string();
    values.push(&user_id_str);

    conn.execute(&sql, params_from_iter(values))
}
```

