I'll write a Go function that builds a dynamic WHERE clause based on the provided filters, using parameterized queries for safety.

```go
package main

import (
	"database/sql"
	"strings"
)

type Customer struct {
	ID         int
	Name       string
	Status     string
	City       string
	SignupYear int
}

func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	query := "SELECT id, name, status, city, signup_year FROM customers"

	var args []interface{}
	var conditions []string

	for key, value := range filters {
		switch key {
		case "status", "city", "signup_year":
			conditions = append(conditions, key+" = ?")
			args = append(args, value)
		}
	}

	if len(conditions) > 0 {
		query += " WHERE " + strings.Join(conditions, " AND ")
	}

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var customers []Customer
	for rows.Next() {
		var c Customer
		if err := rows.Scan(&c.ID, &c.Name, &c.Status, &c.City, &c.SignupYear); err != nil {
			return nil, err
		}
		customers = append(customers, c)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return customers, nil
}
```

Key features:
- **Dynamic WHERE clause**: Only builds conditions for keys actually present in the filters map
- **Safe query building**: Uses parameterized queries (?) to prevent SQL injection
- **Whitelist validation**: The switch statement only allows "status", "city", and "signup_year"
- **Empty map support**: Returns all rows when filters is empty
- **Proper error handling**: Defers closing rows and checks for iteration errors

