```rust
use std::collections::HashMap;
use rusqlite::Connection;

fn update_user_profile(
    conn: &Connection,
    user_id: i64,
    fields: &HashMap<String, String>,
) -> rusqlite::Result<()> {
    if fields.is_empty() {
        return Ok(());
    }

    let mut set_clauses = Vec::new();
    let mut params: Vec<Box<dyn rusqlite::ToSql>> = Vec::new();

    for (key, value) in fields.iter() {
        set_clauses.push(format!("{} = ?", key));
        params.push(Box::new(value.clone()));
    }

    params.push(Box::new(user_id));

    let query = format!(
        "UPDATE users SET {} WHERE id = ?",
        set_clauses.join(", ")
    );

    let mut stmt = conn.prepare(&query)?;
    let param_refs: Vec<&dyn rusqlite::ToSql> = params.iter().map(|p| p.as_ref()).collect();
    stmt.execute(param_refs.as_slice())?;
    Ok(())
}
```

**Key points:**
- Returns `rusqlite::Result<()>` to propagate database errors
- Early return if `fields` is empty (no updates needed)
- Builds SET clauses dynamically from HashMap keys
- Collects values in order into `params` vector, with user_id last for the WHERE clause
- Uses `Box<dyn rusqlite::ToSql>` to handle a dynamic number of parameters
- All values are parameterized to prevent SQL injection via values

**Security note:** Column names cannot be parameterized in SQL, so if they come from untrusted input, validate them against an allowlist first.

