I'll write a Go function that dynamically builds a SQL query based on the provided filters.

```go
package main

import (
    "database/sql"
    "strings"
)

type Customer struct {
    ID         int
    Name       string
    Status     string
    City       string
    SignupYear int
}

func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
    query := "SELECT id, name, status, city, signup_year FROM customers"
    var conditions []string
    var args []interface{}

    // Build WHERE conditions dynamically based on present filters
    if val, ok := filters["status"]; ok {
        conditions = append(conditions, "status = ?")
        args = append(args, val)
    }
    if val, ok := filters["city"]; ok {
        conditions = append(conditions, "city = ?")
        args = append(args, val)
    }
    if val, ok := filters["signup_year"]; ok {
        conditions = append(conditions, "signup_year = ?")
        args = append(args, val)
    }

    // Add WHERE clause if any conditions exist
    if len(conditions) > 0 {
        query += " WHERE " + strings.Join(conditions, " AND ")
    }

    rows, err := db.Query(query, args...)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var customers []Customer
    for rows.Next() {
        var c Customer
        if err := rows.Scan(&c.ID, &c.Name, &c.Status, &c.City, &c.SignupYear); err != nil {
            return nil, err
        }
        customers = append(customers, c)
    }

    if err = rows.Err(); err != nil {
        return nil, err
    }

    return customers, nil
}
```

The function:
- Builds a base SELECT query
- Checks which filter keys are present in the map
- Appends corresponding WHERE conditions with parameterized values (using `?` placeholders to prevent SQL injection)
- Joins conditions with AND if multiple filters exist
- Returns all rows when the filters map is empty
- Scans results into Customer structs

Example usage:
