use rusqlite::{Connection, Result};
use std::collections::HashMap;

fn update_user_profile(
    conn: &Connection,
    user_id: i64,
    fields: &HashMap<String, String>,
) -> Result<usize> {
    if fields.is_empty() {
        return Ok(0);
    }

    // Validate column names to prevent SQL injection
    for col_name in fields.keys() {
        if !is_valid_identifier(col_name) {
            return Err(rusqlite::Error::InvalidQuery);
        }
    }

    // Build SET clause and collect values in consistent order
    let mut set_parts = Vec::new();
    let mut values: Vec<&str> = Vec::new();

    for (col, val) in fields.iter() {
        set_parts.push(format!("{} = ?", col));
        values.push(val.as_str());
    }

    let sql = format!(
        "UPDATE users SET {} WHERE id = ?",
        set_parts.join(", ")
    );

    // Execute with parameterized values
    let mut stmt = conn.prepare(&sql)?;

    let mut params: Vec<&dyn rusqlite::ToSql> = values.iter()
        .map(|v| v as &dyn rusqlite::ToSql)
        .collect();
    params.push(&user_id);

    stmt.execute(rusqlite::params_from_iter(params))
}

fn is_valid_identifier(s: &str) -> bool {
    !s.is_empty() && s.chars().all(|c| c.is_alphanumeric() || c == '_')
}
```

