type Customer struct {
	ID         int
	Status     string
	City       string
	SignupYear int
}

// FindCustomers queries the customers table, applying an equality WHERE
// condition only for the filter keys that are present in the map. An empty
// map returns every row.
func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	// Whitelist of allowed filter keys mapped to their column names. This
	// prevents untrusted map keys from ever reaching the SQL text.
	columns := map[string]string{
