	if !ok || email == "" {
		return 0, fmt.Errorf("email is required")
	}
	name := form["name"] // optional

	// Parameterized query: values are bound, never concatenated,
	// so form input can't alter the SQL statement.
	const query = `INSERT INTO users (email, name) VALUES (?, ?)`

	result, err := db.Exec(query, email, name)
	if err != nil {
		return 0, fmt.Errorf("insert user: %w", err)
	}

	id, err := result.LastInsertId()
	if err != nil {
		return 0, fmt.Errorf("get last insert id: %w", err)
	}

	return id, nil
}
```

